# Shape implementations - cross-module inheritance and interface implementation
# Imports from both types and interfaces

from types import Point, Color, Dimensions, ORIGIN
from interfaces import IDrawable, ITransformable, IMeasurable

@abstract
class Shape(IDrawable, ITransformable, IMeasurable):
    _color: Color
    _position: Point

    def __init__(self, color: Color, position: Point):
        self._color = color
        self._position = position

    @virtual
    def draw(self) -> str:
        return "Shape"

    @virtual
    def translate(self, dx: float, dy: float) -> None:
        self._position = Point(self._position.x + dx, self._position.y + dy)

    @abstract
    def scale(self, factor: float) -> None:
        ...

    @abstract
    def area(self) -> float:
        ...

    @abstract
    def perimeter(self) -> float:
        ...

class Circle(Shape):
    _radius: float

    def __init__(self, color: Color, position: Point, radius: float):
        super().__init__(color, position)
        self._radius = radius

    @override
    def draw(self) -> str:
        return "Circle(r=" + str(self._radius) + ")"

    @override
    def scale(self, factor: float) -> None:
        self._radius = self._radius * factor

    @override
    def area(self) -> float:
        return 3.14159 * self._radius * self._radius

    @override
    def perimeter(self) -> float:
        return 2.0 * 3.14159 * self._radius

class Rectangle(Shape):
    _width: float
    _height: float

    def __init__(self, color: Color, position: Point, dims: Dimensions):
        super().__init__(color, position)
        self._width = dims.width
        self._height = dims.height

    @override
    def draw(self) -> str:
        return "Rectangle(w=" + str(self._width) + ",h=" + str(self._height) + ")"

    @override
    def scale(self, factor: float) -> None:
        self._width = self._width * factor
        self._height = self._height * factor

    @override
    def area(self) -> float:
        return self._width * self._height

    @override
    def perimeter(self) -> float:
        return 2.0 * (self._width + self._height)
